// Mode: Run Once for All Items
// Iterates over every Greenhouse Fetcher response, pairs each with its source
// company via pairedItem (robust against per-item ordering changes), and emits
// one item per job. Empty company boards contribute zero items, which is fine.

const responses = $input.all();
const companies = $('Set Inputs').all().map(i => i.json);

const decodeEntities = (s) => String(s || '')
  .replace(/&amp;/g, '&')
  .replace(/&nbsp;/g, ' ')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&#x27;/g, "'");

const stripHtml = (html) => decodeEntities(html)
  .replace(/<[^>]*>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const isRemote = (job) => {
  const loc = String(job?.location?.name || '').toLowerCase();
  return loc.includes('remote');
};

const allNormalized = [];

for (const inp of responses) {
  const response = inp.json || {};
  // Pair this response with its source company via pairedItem.
  // Falls back to index 0 if pairedItem is missing (shouldn't happen from HTTP).
  const sourceIdx = inp.pairedItem?.item ?? 0;
  const company = companies[sourceIdx] || {};

  const jobs = Array.isArray(response.jobs) ? response.jobs : [];

  const normalized = jobs.map(job => ({
    company: company.company_name || '',
    title: String(job.title || '').trim(),
    url: String(job.absolute_url || '').trim(),
    description_html: decodeEntities(job.content),
    description: stripHtml(job.content),
    location: String(job.location?.name || '').trim(),
    remote: isRemote(job),
    salary_text: '',
    employment_type: '',
    source: 'greenhouse',
    posted_at: job.updated_at || job.first_published_at || ''
  }));

  console.log(`[Greenhouse Parse] ${company.company_name || '(unknown)'} (${company.slug || '?'}): ${jobs.length} raw, ${normalized.length} normalized`);

  for (const j of normalized) allNormalized.push(j);
}

console.log(`[Greenhouse Parse] total: ${responses.length} boards â†’ ${allNormalized.length} jobs`);

return allNormalized.map(j => ({ json: { ...j, _type: 'job' } }));

const config = $('Trigger').first().json.config || {};
const watchlist = $('Trigger').first().json.watchlist || [];

const orderRaw = config.discovery_fetcher_order || '';
const enabledSources = String(orderRaw)
  .split(/[;,]/)
  .map(s => s.trim().toLowerCase())
  .filter(s => s.length > 0);

if (!enabledSources.includes('greenhouse')) {
  console.log('[Greenhouse] Disabled via discovery_fetcher_order â€” skipping');
  return [];
}

const thresholdRaw = Number(config.discovery_priority_threshold);
const priorityThreshold = isNaN(thresholdRaw) ? 999 : thresholdRaw;

const companies = watchlist
  .filter(c => {
    if (!c) return false;
    if (String(c.greenhouse_slug || '').trim().length === 0) return false;
    const p = Number(c.priority);
    const priority = isNaN(p) ? 999 : p;
    return priority <= priorityThreshold;
  })
  .map(c => ({
    company_name: String(c.company_name || '').trim(),
    slug: String(c.greenhouse_slug || '').trim()
  }));

if (companies.length === 0) {
  console.log(`[Greenhouse] No companies match priority <= ${priorityThreshold} with greenhouse_slug â€” skipping`);
  return [];
}

console.log(`[Greenhouse] Fetching ${companies.length} boards (priority <= ${priorityThreshold})`);
return companies.map(c => ({ json: c }));

const company = $('Set Inputs').item.json;
const runId = $('Trigger').first().json.run_id || '';
const errPayload = $input.first().json || {};
const errObj = errPayload.error || {};

const statusCode = String(
  errObj.httpCode ||
  errObj.status ||
  errObj.cause?.response?.status ||
  ''
);
const message = String(errObj.message || 'Unknown error').substring(0, 500);

console.log(`[Greenhouse] Fetch failed for ${company.company_name} (${company.slug}): ${statusCode} ${message}`);

return [{
  json: {
    _type: 'failure',
    run_id: runId,
    discovered_at: new Date().toISOString(),
    source: 'greenhouse',
    company: company.company_name || '',
    slug: company.slug || '',
    status_code: statusCode,
    error_message: message
  }
}];
